INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Multi-model chat$q$, $q$Switch between GPT-4o, OpenAI's o1, Claude 3.5 Sonnet, and Gemini within a single conversation to pick the best model for a given task.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Real-time web search grounding$q$, $q$Pulls live, current information from the web into chat responses instead of relying only on a static training cutoff.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Image generation$q$, $q$Generates images from text prompts using models such as Flux 1.1 and DALL-E 3 on paid plans, and Stable Diffusion on the free tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$File and document chat$q$, $q$Upload PDFs, spreadsheets, presentations, and images to ask questions and extract insights directly from your own files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Brand voice customization$q$, $q$Set a consistent tone (professional, conversational, or casual) so generated content matches a brand's established style.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Google Search Console integration$q$, $q$Pull SEO performance and search data directly into a chat session for analysis without leaving Chatsonic.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$WordPress integration$q$, $q$Publish finished content straight to a connected WordPress site from within the chat workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Canvas workspace$q$, $q$A dedicated writing and editing surface for longer-form content and collaborative drafting, similar to canvas/artifact features in other AI tools.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Auto Prompt Optimizer$q$, $q$Automatically refines user prompts to help produce more accurate and relevant AI responses.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Access to several leading AI models (GPT-4o, o1, Claude 3.5, Gemini) under one subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Real-time web search reduces outdated or hallucinated answers on current topics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Bundled image generation and document/file chat in the same interface$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Low entry price on the Individual plan compared to subscribing to multiple AI chatbots separately$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Direct integrations with Google Search Console and WordPress streamline content-to-publish workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Free plan is limited to lighter models (GPT-4o mini, Claude Haiku) with fewer capabilities$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Some advertised features are marked 'coming soon,' suggesting an incomplete rollout$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Interface can feel more complex and marketing-tool-heavy than a focused, minimalist chatbot$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Writesonic's broader repositioning toward an AI search visibility (GEO) platform makes long-term chat-focused investment less certain$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Not positioned for developers needing granular API/model control the way direct provider APIs are$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$What is Chatsonic?$q$, $q$Chatsonic is Writesonic's AI chatbot that combines access to multiple AI models (GPT-4o, o1, Claude 3.5, Gemini) with real-time web search, image generation, and marketing-focused integrations in a single chat interface.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Is Chatsonic free to use?$q$, $q$Yes, Chatsonic offers a free plan with access to lighter models like GPT-4o mini and Claude Haiku, basic web search, and limited file analysis. Full model access and unlimited file analysis require the paid Individual plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Does Chatsonic have real-time internet access?$q$, $q$Yes. Real-time web search is one of Chatsonic's core differentiators, letting it pull current information from the web into chat responses rather than relying only on a static training dataset.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$What AI models power Chatsonic?$q$, $q$Chatsonic gives users access to OpenAI's GPT-4o and o1, Anthropic's Claude 3.5 Sonnet, and Google's Gemini, plus image models like Flux 1.1 and DALL-E 3 on paid plans.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$How is Chatsonic different from Writesonic?$q$, $q$Writesonic is the parent platform focused on content generation and, more recently, AI search visibility (GEO). Chatsonic is its chat product, offering a conversational interface with multi-model access and real-time search layered on top of that same platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Real-time research for marketing content$q$, $q$Marketers use Chatsonic's web-connected chat to research current trends, competitor moves, and news before drafting campaign copy or blog content.$q$, $q$Marketing teams and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$SEO-informed content drafting$q$, $q$By connecting Google Search Console data directly into chat, users can identify underperforming keywords and draft optimized content in the same session.$q$, $q$SEO specialists and in-house content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Document and report analysis$q$, $q$Professionals upload PDFs, spreadsheets, and presentations to ask questions, summarize findings, and extract key data points without manual review.$q$, $q$Consultants, analysts, and small business owners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Multi-model everyday assistant$q$, $q$Individuals who want one subscription that covers GPT, Claude, and Gemini use Chatsonic as a general chat assistant with added image generation.$q$, $q$Freelancers and individual AI power users$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Free$q$, $q$$0$q$, NULL, $q$["Access to GPT-4o mini and Claude Haiku","Basic web search and content creation","Limited file analysis","Basic brand voice customization","Image generation with Stable Diffusion","Limited access to marketing tool integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$Individual$q$, $q$$16/month$q$, $q$annual$q$, $q$["Full access to GPT-4o, o1, Claude 3.5 Sonnet, and Gemini","Advanced web search and real-time data gathering","Unlimited file analysis (PDFs, images, PPTs, CSVs)","Advanced brand voice and style customization","Full integration with Google Search Console and WordPress","Image generation with Flux 1.1 and DALL-E 3","Canvas feature for writing and coding projects","Auto Prompt Optimizer"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chatsonic is the AI chat product built by Writesonic, the San Francisco-founded content and SEO software company started in 2020. Launched in late 2022 as a direct response to ChatGPT's launch, Chatsonic was positioned from day one as a chatbot that could do what early ChatGPT couldn't: pull live, current information from the web instead of relying solely on a static training cutoff. Since then it has evolved alongside Writesonic's broader platform, and today it sits inside Writesonic as an 'AI Marketing Agent' rather than a standalone general-purpose assistant.$q$, $q$At its core, Chatsonic lets users converse with and switch between several frontier language models, including OpenAI's GPT-4o and o1, Anthropic's Claude 3.5 Sonnet, and Google's Gemini, all from a single interface. Layered on top of that model access are real-time web search grounding, image generation, file and document chat, and integrations with marketing tools like Google Search Console and WordPress. The result is less a pure chatbot and more a research-and-content workstation aimed at people who need current information and publishable output in the same session.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$who-its-for$q$, $q$Who Chatsonic Is For$q$, 2, ARRAY[$q$Chatsonic is best suited to marketers, SEO specialists, content creators, and small agency teams who already lean on Writesonic (or are considering it) for content production and want their chat assistant tied into the same workflow. Because it bundles real-time search, brand-voice customization, and direct WordPress/Search Console connections, it appeals to people who want to go from research to a published, on-brand draft without switching tools.$q$, $q$It also suits users who want access to multiple leading AI models without paying for separate ChatGPT Plus, Claude Pro, and Gemini subscriptions individually. For a solo creator or freelancer who mainly needs current-events-aware answers, quick image generation, and the ability to chat with PDFs or spreadsheets, the low-cost Individual plan can be an efficient way to cover several bases at once.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Chatsonic is a weaker fit for anyone looking for a pure, no-frills conversational assistant. Because Writesonic has repositioned around AI search visibility (GEO) and marketing workflows, the surrounding product now leans heavily toward content and SEO teams, and some Chatsonic-specific capabilities are labeled 'coming soon,' which suggests the chat experience itself is not the company's current priority.$q$, $q$Developers and technical users who want deep API control, fine-grained model parameters, or the very latest model releases the moment they ship are usually better served going directly to OpenAI, Anthropic, or Google. Similarly, privacy-sensitive enterprise buyers with strict compliance requirements should evaluate Writesonic's enterprise-tier data handling directly, since the consumer-facing Free and Individual plans are not built around that use case.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of Chatsonic is multi-model access: users can toggle between GPT-4o, OpenAI's o1 reasoning model, Claude 3.5 Sonnet, and Gemini within the same chat thread, choosing whichever model suits a given task. This is paired with real-time web search, which grounds answers in current information pulled from live search results rather than a frozen training set, reducing outdated or hallucinated responses on time-sensitive topics.$q$, $q$Beyond text chat, Chatsonic supports image generation through models like Flux 1.1 and DALL-E 3, plus document and file chat that lets users upload PDFs, spreadsheets, presentations, and images to ask questions against their own content. Brand voice and style customization allows teams to keep tone consistent across professional, conversational, or casual registers, while a Canvas-style workspace supports longer collaborative writing and editing sessions.$q$, $q$Marketing-specific integrations round out the feature set: direct connections to Google Search Console and WordPress let users pull SEO performance data into a chat session or push finished content straight to publish, cutting out the copy-paste steps between research, drafting, and shipping content.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a148f101-9c66-4591-aec9-b3207ca40a0e', $q$the-chatsonic-experience$q$, $q$The Chatsonic Experience$q$, 2, ARRAY[$q$Using Chatsonic feels closer to working inside a marketing content suite than chatting with a standalone assistant like ChatGPT. The interface surfaces model switching, web search toggles, file uploads, and integration settings alongside the conversation itself, which gives power users a lot of control but can feel busier than a minimalist chatbot to someone who just wants quick answers.$q$, $q$The free tier, limited to lighter models like GPT-4o mini and Claude Haiku with basic web search, is enough to get a feel for the product, but the meaningful jump in model quality, unlimited file analysis, and full integrations happens on the paid Individual plan. Because Chatsonic is developed and priced as part of Writesonic's wider platform, the overall experience is shaped by where Writesonic is investing next, so features and positioning have shifted noticeably since the product's 2022 launch and are likely to keep evolving.$q$]::text[], 4);
