INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Conversational AI chat$q$, $q$Natural back-and-forth conversation for answering questions, brainstorming, and general assistance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Document analysis$q$, $q$Upload and analyze PDFs, spreadsheets, and other documents for summaries, extraction, and Q&A.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Image understanding$q$, $q$Upload images for Claude to describe, analyze, or reason about as part of a conversation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Extended context conversations$q$, $q$Handle long documents and lengthy conversation histories while retaining relevant context.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Coding assistance$q$, $q$Write, explain, debug, and refactor code across many popular programming languages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Claude Code$q$, $q$An agentic coding tool that integrates Claude into terminal and IDE workflows for developers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Projects$q$, $q$Organize related conversations, files, and custom instructions around a specific topic or workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Artifacts$q$, $q$View and iterate on generated code, documents, or interactive content in a dedicated side panel.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Developer API$q$, $q$Programmatic access to Claude for building custom applications and integrations, billed on usage.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Team and enterprise administration$q$, $q$Shared workspaces, centralized billing, and admin controls for organizations on higher-tier plans.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Strong performance on writing, reasoning, and long-document analysis tasks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Free tier available for casual or first-time users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Projects and Artifacts add useful structure beyond basic chat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Dedicated Claude Code tooling for developers who want AI embedded in their coding workflow$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Available across web, desktop (Mac/Windows), and mobile (iOS/Android) apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Free tier usage limits can be restrictive for heavy users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Like all AI assistants, responses can occasionally be inaccurate and should be verified$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Some advanced features and higher usage limits require a paid plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise-grade compliance details require direct review with Anthropic for regulated industries$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$No official interface localization beyond English at the product level$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$What is Claude?$q$, $q$Claude is Anthropic's AI assistant, offering conversational chat, document and image analysis, coding help, and productivity features like Projects and Artifacts through web, desktop, and mobile apps, as well as a developer API.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Is Claude free to use?$q$, $q$Yes, Claude offers a free tier with usage limits. Paid plans (Pro, Team, and Enterprise) provide higher usage limits and additional features.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$How much does Claude Pro cost?$q$, $q$Claude's Pro plan starts at $20 per month for individual users, offering higher usage limits and access to additional features compared to the free tier.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Can Claude help with coding?$q$, $q$Yes, Claude can write, explain, and debug code, and Anthropic also offers Claude Code, a dedicated agentic coding tool that integrates into terminal and IDE workflows.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Who created Claude?$q$, $q$Claude is developed by Anthropic, an AI safety and research company founded in 2021 and headquartered in San Francisco, California.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Writing and editing assistance$q$, $q$Drafting, editing, and refining emails, reports, articles, and other written content.$q$, $q$Writers, marketers, and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Document summarization and analysis$q$, $q$Uploading long reports, contracts, or research papers for summaries and question answering.$q$, $q$Researchers, analysts, and legal or business professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Software development$q$, $q$Writing, explaining, and debugging code, and using Claude Code for agentic assistance inside a development workflow.$q$, $q$Software developers and engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Custom AI-powered applications$q$, $q$Integrating Claude's API into internal tools or customer-facing products for conversational or document-processing features.$q$, $q$Developers and businesses building AI-powered products$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Free$q$, $q$$0$q$, NULL, $q$["Access to Claude chat","Limited usage per day","Basic document and image uploads"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Pro$q$, $q$$20/month$q$, $q$monthly$q$, $q$["Higher usage limits than Free","Access to Projects and Artifacts","Priority access during high-traffic periods"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Team$q$, $q$Contact for current pricing$q$, $q$monthly or annual$q$, $q$["Everything in Pro","Shared workspace for teams","Centralized billing and admin controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise$q$, $q$Custom / Contact sales$q$, NULL, $q$["Advanced security and compliance options","Higher usage limits","Dedicated support and admin tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Claude is the conversational AI assistant built by Anthropic, a research and safety-focused AI company founded in 2021 by siblings Dario Amodei and Daniela Amodei along with several colleagues who previously worked on large language models elsewhere. Claude is available through the claude.ai web app, native desktop apps for Mac and Windows, and mobile apps for iOS and Android, as well as through Anthropic's API for developers who want to embed Claude's capabilities into their own products.$q$, $q$At its core, Claude is designed for natural-language conversation, but its practical use spans far beyond simple chat. It can read and reason over uploaded documents, analyze images, summarize long text, write and debug code, and hold extended back-and-forth conversations that retain context over long sessions. Anthropic has also built out a broader assistant experience around the base model, including Projects for organizing related work and persistent context, and Artifacts, a feature that lets Claude generate and display standalone content like code, documents, or interactive components in a dedicated panel alongside the conversation.$q$, $q$For developers and technical teams, Anthropic also offers Claude Code, a command-line and IDE-integrated coding agent that uses Claude to read, write, and refactor code directly inside a developer's existing workflow. Combined, these products position Claude as both a general-purpose assistant for everyday knowledge work and a specialized tool for software development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$who-claude-is-for$q$, $q$Who Claude Is For$q$, 2, ARRAY[$q$Claude is well suited to knowledge workers, writers, researchers, and students who need help drafting, editing, summarizing, or reasoning through long or complex documents. Its ability to handle extended context makes it a strong fit for anyone working with lengthy reports, contracts, research papers, or multi-file codebases where keeping track of earlier context matters.$q$, $q$Software developers and technical teams are another core audience, particularly those who want an AI assistant integrated into their coding workflow through Claude Code or the API, rather than a chat-only experience. Businesses building their own AI-powered features can also use Claude's API and developer tools to add conversational or document-processing capabilities to their own products.$q$, $q$Because Claude offers a free tier alongside paid plans, it's accessible to individuals just experimenting with AI assistants as well as professionals and teams who need higher usage limits, more advanced features, or centralized billing and administration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who need guaranteed real-time, always-current information without any caveats may find general-purpose AI chatbots like Claude less reliable than a dedicated search engine or specialized data provider, since AI assistants can still make mistakes or present outdated information despite web search integrations.$q$, $q$Organizations with strict, highly specialized compliance or data-residency requirements should carefully review Anthropic's enterprise data handling and security terms before adopting Claude for regulated workflows, as with any third-party AI vendor. Similarly, teams looking for a deeply vertical, industry-specific tool (e.g., purpose-built legal or medical software) may find a specialized product a better fit than a general-purpose assistant.$q$, $q$Users on a strict no-cost budget who need heavy, high-volume usage may also find the free tier's limits restrictive and should compare pricing against other general AI assistants before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Claude's core capabilities include natural conversational chat, document and image understanding (users can upload PDFs, spreadsheets, and images for analysis), long-context reasoning that allows it to work with large volumes of text in a single conversation, and strong coding assistance for writing, explaining, and debugging code across many programming languages.$q$, $q$Anthropic has layered several product-level features on top of the base assistant: Projects let users group conversations, files, and custom instructions around a specific topic or workflow so Claude retains relevant context; Artifacts render generated content like code snippets, documents, or simple interactive UI in a separate view for easier iteration; and Claude Code brings agentic coding assistance directly into terminal and IDE workflows. Team and Enterprise plans add collaboration features such as shared workspaces, centralized billing, and administrative controls.$q$, $q$Developers can also access Claude programmatically through Anthropic's API, enabling integration into custom applications, internal tools, and third-party products, with usage-based pricing separate from the consumer subscription plans.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$the-claude-experience$q$, $q$The Claude Experience$q$, 2, ARRAY[$q$Using Claude generally feels straightforward: the interface centers on a clean chat window where users type questions, paste text, or upload files, and Claude responds conversationally. The addition of Projects and Artifacts gives the experience more structure than a simple chatbot, letting users build ongoing, context-aware workflows rather than starting from scratch in every conversation.$q$, $q$Anthropic has positioned Claude with a particular emphasis on helpfulness balanced with safety and honesty in its responses, reflecting the company's broader research focus on AI alignment. In practice, this shows up as an assistant that tends to be thoughtful and careful in how it handles ambiguous or sensitive requests.$q$, $q$Overall, the experience is designed to scale from casual everyday use on the free tier to more demanding professional and developer workflows on paid plans, with the underlying assistant, Projects, Artifacts, and coding tools forming a consistent experience across the web, desktop, and mobile apps.$q$]::text[], 4);
