INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Time tracking$q$, $q$Start/stop timer, manual entry, calendar view, and an auto-tracker that detects time spent in other desktop apps and websites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Timesheets$q$, $q$Weekly timesheet views for logging and reviewing team hours, with locking and approval workflows on higher tiers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Reporting$q$, $q$Summary, detailed, and weekly reports with PDF/CSV/Excel export for analyzing time by project, client, or team member.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Invoicing$q$, $q$Convert tracked billable hours directly into client invoices without re-entering data in separate billing software.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Project budgeting and estimates$q$, $q$Set time or cost budgets per project and track progress against estimates to flag overruns early.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Scheduling and time off$q$, $q$Plan team capacity ahead of time and manage time-off requests and approvals alongside tracked hours.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$GPS tracking and kiosk mode$q$, $q$Location-based mobile check-ins and a shared-device time clock for field or shift-based teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Integrations and API$q$, $q$Connects with 80+ third-party apps plus an open API and webhooks for custom workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Cross-platform apps$q$, $q$Native apps for Windows, Mac, iOS, and Android, plus browser extensions, all syncing the same tracked data.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Admin controls$q$, $q$Bulk time-entry editing, time audit trails, custom fields, and (on Enterprise) SSO and audit logs.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Usable free plan with unlimited time tracking and projects for small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Clean, low-learning-curve interface for both individuals and admins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Consistent cross-platform apps across web, desktop, mobile, and browser$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Wide integration library (80+ apps) plus an open API$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Gradual, transparent per-tier pricing rather than a steep jump to enterprise-only plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Free plan is now capped at 5 users (changed from unlimited in April 2026), which raises costs for larger free-tier teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Invoicing, approvals, budgeting, and GPS tracking require paid Standard/Pro tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Free-tier reporting is limited to a 1-month data range$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$No native payroll processing — pairs with, rather than replaces, payroll tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Advanced admin features (kiosk, custom fields, SSO) are spread across several paid tiers, requiring plan comparison to find the right fit$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Is Clockify free to use?$q$, $q$Yes, Clockify has a free plan with unlimited time tracking and unlimited projects, but as of April 2026 it is limited to up to 5 users; larger teams need a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Did Clockify remove unlimited free users?$q$, $q$Yes. Clockify was previously known for unlimited users on its free plan, but in April 2026 the company introduced a 5-user cap on the free tier.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Does Clockify support invoicing?$q$, $q$Yes, invoicing is available starting on the Standard plan, letting teams turn tracked billable hours into client invoices.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Does Clockify have GPS tracking for mobile employees?$q$, $q$Yes, GPS location tracking for mobile check-ins is included starting on the Pro plan, along with a kiosk mode for shared time-clock devices.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$What platforms does Clockify support?$q$, $q$Clockify is available as a web app, desktop apps for Windows and Mac, mobile apps for iOS and Android, and browser extensions.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Client-billable time tracking for agencies$q$, $q$Agencies and consultancies track billable hours by client and project, then convert them directly into invoices.$q$, $q$Agencies and professional-services teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Remote team time visibility$q$, $q$Distributed teams log hours across time zones and managers review consolidated timesheets and reports.$q$, $q$Remote and distributed teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Field service and shift tracking$q$, $q$Field staff clock in via GPS-verified mobile check-ins or a shared kiosk device at a job site.$q$, $q$Field service and shift-based businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Freelance and small-team project tracking$q$, $q$Freelancers and small teams track unlimited projects on the free plan without upfront cost.$q$, $q$Freelancers and small teams (up to 5 users)$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Free$q$, $q$$0$q$, NULL, $q$["Up to 5 users","Unlimited time tracking","Unlimited projects","Reports (1-month range)","PDF export","API access (30 requests/hour)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Basic$q$, $q$$3.99/user/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Everything in Free","Kiosk access","Bulk time-entry editing","Time audit","CSV/Excel export","Project templates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Standard$q$, $q$$5.49/user/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Everything in Basic","Time-off policies","Invoicing","Approval workflows","Timesheet locking","Manager roles"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$Pro$q$, $q$$7.99/user/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Everything in Standard","Scheduling","Expense tracking","Budget and estimate tools","Custom fields","GPS tracking","Forecasting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clockify is a time-tracking and workforce-visibility platform built by CAKE.com (formerly COING), a bootstrapped, Serbian-founded software company that also makes the team chat app Pumble and the project-management tool Plaky. Founder Nenad Milanović ran COING as a consultancy for years to self-fund product experiments, and Clockify — launched in 2017 after several earlier attempts — became the breakout hit, growing into one of the most widely adopted time trackers on the market.$q$, $q$At its core, Clockify lets individuals and teams log work hours with a start/stop timer or manual entry, organize that time by client, project, and task, and turn the resulting data into timesheets, reports, and client-ready invoices. It ships as a web app, desktop apps for Windows and Mac, mobile apps for iOS and Android, and browser extensions that auto-detect time spent in other apps and sites.$q$, $q$In April 2026, Clockify changed a long-standing differentiator: its free plan, previously known for allowing unlimited users, now caps out at 5 users. The free tier still includes unlimited time tracking and unlimited projects, but teams larger than five people now need a paid plan to keep using Clockify at all.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$who-its-for$q$, $q$Who Clockify Is For$q$, 2, ARRAY[$q$Clockify fits small-to-midsize teams, agencies, consultancies, and freelancers that need dependable, low-friction time tracking without adopting a heavier all-in-one work-management suite. Its pricing scales gradually by feature tier rather than jumping straight to enterprise-only packaging, which makes it approachable for teams that are budget-conscious but still need real reporting and admin controls.$q$, $q$It's a particularly strong fit for organizations that bill clients by the hour — agencies, law firms, freelance collectives, and professional-services teams — since Standard and Pro tiers add invoicing, approval workflows, timesheet locking, and budget/estimate tracking on top of the raw time data.$q$, $q$Distributed and field-based teams also benefit: Pro and Enterprise plans add GPS location tracking for mobile check-ins and a kiosk/time-clock mode useful for shared devices, making Clockify workable for site-based or shift-based staff, not just desk workers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that specifically need to track time for more than five people at zero cost should look elsewhere now that Clockify's free plan is capped; the tool's biggest historical selling point (unlimited free users) no longer applies, so cost-sensitive teams larger than five should compare against other free-tier time trackers before assuming Clockify will be free.$q$, $q$Organizations that need deep native payroll processing, HR case management, or advanced resource-capacity planning will find Clockify's scope narrower than dedicated HR or PSA (professional-services-automation) platforms — Clockify tracks and reports time and expenses well, but it is not a payroll or HR system on its own.$q$, $q$Companies wanting a single bundled communication-plus-tasks-plus-time suite may find it simpler to evaluate the CAKE.com bundle (Clockify, Pumble, and Plaky together) or a competing all-in-one product, rather than layering Clockify's own upgrade tiers on top of separately priced sister apps.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Time capture is the foundation: a start/stop timer, manual entry, calendar view, and an auto-tracker that logs time spent in desktop apps and websites so users can convert idle activity into tracked entries. A Pomodoro timer and idle-detection reminders round out the individual-tracking experience.$q$, $q$On the management side, Clockify offers timesheets, summary/detailed/weekly reports with export options, project and task budgeting, expense tracking, custom fields, and time-off/approval workflows on higher tiers. Invoicing lets teams turn billable hours directly into client invoices, while scheduling tools help managers plan team capacity ahead of time.$q$, $q$Administrative and integration features include kiosk mode for shared time clocks, GPS tracking for mobile check-ins, single sign-on and audit logs on Enterprise, an open API, webhooks, and integrations with more than 80 third-party apps, covering project management, accounting, and communication tools teams already use.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('727ce456-3ada-4396-a467-30164d11f40e', $q$the-clockify-experience$q$, $q$The Clockify Experience$q$, 2, ARRAY[$q$Day to day, Clockify's interface stays close to its original selling point: a simple timer and clean reports, without forcing users through a steep setup process. New users can generally start tracking time within minutes, and the feature tiers are additive rather than restructuring the core workflow, so upgrading doesn't require relearning the tool.$q$, $q$Cross-platform consistency is a strength — the same time data syncs across the web app, Windows and Mac desktop apps, iOS and Android apps, and browser extensions, which matters for teams mixing office and field work. Clockify also provides 24/7 support via email, chat, and phone even on the free plan.$q$, $q$Because Clockify sits inside the CAKE.com product family, teams already using Pumble for chat or Plaky for project boards get native integrations between the three tools, letting time tracking connect to conversations and task boards without custom middleware — a natural extension path for teams that outgrow a single point tool.$q$]::text[], 4);
